}

#[test]
fn rbtdtu_case_patterns_suppressed_bodies_scanned() {
    // Patterns (200, *) are not commands; branch bodies (echo, buc_die) are.
    let src = "case $x in\n  200) echo hi ;;\n  *) buc_die ;;\nesac";
    assert_eq!(cmds(src), vec!["echo", "buc_die"]);
}

